parameters.jsCode:
const item = $input.item.json;

const raw = item.output?.[0]?.content?.[0]?.text || '';

let parsed;

try {
  parsed = JSON.parse(raw);
} catch (error) {
  parsed = {
    category: 'Other',
    priority: 'Medium',
    product_area: 'General Platform',
    team: 'Operations Support',
    confidence: 0,
    summary: 'AI classification failed. Manual review required.'
  };
}

const email = $('Set - Normalize Email Data').first().json;

return {
  json: {
    email_subject: email.email_subject,
    email_sender: email.email_sender,
    email_body: email.email_body,
    email_message_id: email.email_message_id,
    received_at: email.received_at,

    category: parsed.category || 'Other',
    priority: parsed.priority || 'Medium',
    product_area: parsed.product_area || 'General Platform',
    team: parsed.team || 'Operations Support',
    confidence: parsed.confidence ?? 0,
    ai_summary: parsed.summary || email.email_subject || 'Support request'
  }
};

const baseUrl = "https://raw.githubusercontent.com/NodrrS/P1_Digital_Workplace_Support_Copilot/main/knowledge-base/";

const articles = {
  "Access Request": "sharepoint-access.md",
  "Permission Request": "permissions-request.md",
  "Publishing Issue": "publishing-issue.md",
  "Training Request": "editor-training.md",
  "Documentation Request": "documentation-request.md",
  "Bug Report": "bug-report.md",
  "Feature Request": "feature-request.md",
  "Other": "general-support.md"
};

const fileName = articles[$json.category] || articles["Other"];

return {
  json: {
    ...$json,
    knowledge_article: fileName,
    article_url: baseUrl + fileName
  }
};

const item = $input.item.json;

const raw = item.output?.[0]?.content?.[0]?.text || '';

let parsed;

try {
  parsed = JSON.parse(raw);
} catch (error) {
  parsed = {
    recommended_resolution: ['Resolution recommendation failed. Manual review required.'],
    knowledge_article: 'Unknown',
    assignment_group: 'Support',
    sla: 'Manual review',
    next_actions: ['Review original request', 'Assign to support team']
  };
}

const email = $('Set - Normalize Email Data').first().json;
const classification = $('Code - Parse Classification').first().json;
const kb = $('Code - Knowledge Base Lookup').first().json;

const formattedResolution = Array.isArray(parsed.recommended_resolution)
  ? parsed.recommended_resolution
      .map((step, index) => `${index + 1}. ${step}`)
      .join('\n')
  : parsed.recommended_resolution || 'Manual review required.';

const formattedNextActions = Array.isArray(parsed.next_actions)
  ? parsed.next_actions.join('\n- ')
  : parsed.next_actions || 'Manual review required.';

const formattedSla = typeof parsed.sla === 'object'
  ? JSON.stringify(parsed.sla)
  : parsed.sla || 'Manual review';

return {
  json: {
    email_subject: email.email_subject,
    email_sender: email.email_sender,
    email_body: email.email_body,
    email_message_id: email.email_message_id,
    received_at: email.received_at,

    category: classification.category,
    priority: classification.priority,
    product_area: classification.product_area,
    team: classification.team,
    confidence: classification.confidence,
    ai_summary: classification.ai_summary,

    recommended_resolution: formattedResolution,
    resolved_knowledge_article: parsed.knowledge_article || kb.knowledge_article || 'Unknown',
    assignment_group: parsed.assignment_group || classification.team || 'Support',
    sla: formattedSla,
    next_actions: formattedNextActions
  }
};
